package provider

import (
	"context"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
)

func TestOpenAIEmbedder_Embed(t *testing.T) {
	// Create a mock server that returns a valid embedding response
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// Verify request
		if r.Method != http.MethodPost {
			t.Errorf("expected POST, got %s", r.Method)
		}
		if r.Header.Get("Authorization") != "Bearer test-key" {
			t.Errorf("unexpected authorization header: %s", r.Header.Get("Authorization"))
		}
		if r.Header.Get("Content-Type") != "application/json" {
			t.Errorf("unexpected content type: %s", r.Header.Get("Content-Type"))
		}

		var req embeddingRequest
		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
			t.Fatalf("failed to decode request: %v", err)
		}
		if req.Model != "text-embedding-3-small" {
			t.Errorf("unexpected model: %s", req.Model)
		}
		if req.Input != "hello world" {
			t.Errorf("unexpected input: %s", req.Input)
		}

		// Return a fake embedding
		embedding := make([]float32, 1536)
		embedding[0] = 0.1
		embedding[1] = 0.2
		embedding[2] = 0.3

		resp := embeddingResponse{
			Data: []struct {
				Embedding []float32 `json:"embedding"`
			}{
				{Embedding: embedding},
			},
		}
		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(resp)
	}))
	defer server.Close()

	// Override the URL by using a custom client that rewrites URLs
	embedder := NewOpenAIEmbedder("test-key",
		WithEmbeddingHTTPClient(server.Client()),
	)
	// Override the URL for testing by replacing the const via a transport wrapper
	origURL := openAIEmbeddingURL
	_ = origURL // suppress unused warning

	// Use a roundtrip wrapper to redirect to test server
	embedder.client.Transport = &urlRewriter{
		target:    server.URL,
		transport: server.Client().Transport,
	}

	vec, err := embedder.Embed(context.Background(), "hello world")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(vec) != 1536 {
		t.Fatalf("expected 1536 dimensions, got %d", len(vec))
	}
	if vec[0] != 0.1 || vec[1] != 0.2 || vec[2] != 0.3 {
		t.Errorf("unexpected embedding values: %v", vec[:3])
	}
}

func TestOpenAIEmbedder_EmptyInput(t *testing.T) {
	embedder := NewOpenAIEmbedder("test-key")
	_, err := embedder.Embed(context.Background(), "")
	if err == nil {
		t.Fatal("expected error for empty input")
	}
	if !strings.Contains(err.Error(), "empty input") {
		t.Errorf("expected 'empty input' error, got: %v", err)
	}
}

func TestOpenAIEmbedder_APIError(t *testing.T) {
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
		w.WriteHeader(http.StatusTooManyRequests)
		_, _ = w.Write([]byte(`{"error": {"message": "rate limited"}}`))
	}))
	defer server.Close()

	embedder := NewOpenAIEmbedder("test-key")
	embedder.client.Transport = &urlRewriter{
		target:    server.URL,
		transport: server.Client().Transport,
	}

	_, err := embedder.Embed(context.Background(), "hello")
	if err == nil {
		t.Fatal("expected error for API error response")
	}
	if !strings.Contains(err.Error(), "api status 429") {
		t.Errorf("expected status 429 error, got: %v", err)
	}
}

func TestOpenAIEmbedder_EmptyResponse(t *testing.T) {
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
		w.Header().Set("Content-Type", "application/json")
		_, _ = w.Write([]byte(`{"data": []}`))
	}))
	defer server.Close()

	embedder := NewOpenAIEmbedder("test-key")
	embedder.client.Transport = &urlRewriter{
		target:    server.URL,
		transport: server.Client().Transport,
	}

	_, err := embedder.Embed(context.Background(), "hello")
	if err == nil {
		t.Fatal("expected error for empty response")
	}
	if !strings.Contains(err.Error(), "empty embedding") {
		t.Errorf("expected 'empty embedding' error, got: %v", err)
	}
}

func TestOpenAIEmbedder_Truncation(t *testing.T) {
	var receivedInput string
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		var req embeddingRequest
		_ = json.NewDecoder(r.Body).Decode(&req)
		receivedInput = req.Input

		embedding := make([]float32, 1536)
		resp := embeddingResponse{
			Data: []struct {
				Embedding []float32 `json:"embedding"`
			}{
				{Embedding: embedding},
			},
		}
		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(resp)
	}))
	defer server.Close()

	embedder := NewOpenAIEmbedder("test-key")
	embedder.client.Transport = &urlRewriter{
		target:    server.URL,
		transport: server.Client().Transport,
	}

	longInput := strings.Repeat("a", maxEmbeddingInputLen+1000)
	_, err := embedder.Embed(context.Background(), longInput)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(receivedInput) != maxEmbeddingInputLen {
		t.Errorf("expected input truncated to %d, got %d", maxEmbeddingInputLen, len(receivedInput))
	}
}

func TestOpenAIEmbedder_Dimensions(t *testing.T) {
	embedder := NewOpenAIEmbedder("test-key")
	if d := embedder.Dimensions(); d != 1536 {
		t.Errorf("expected 1536 dimensions, got %d", d)
	}
}

func TestOpenAIEmbedder_CustomModel(t *testing.T) {
	var receivedModel string
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		var req embeddingRequest
		_ = json.NewDecoder(r.Body).Decode(&req)
		receivedModel = req.Model

		embedding := make([]float32, 1536)
		resp := embeddingResponse{
			Data: []struct {
				Embedding []float32 `json:"embedding"`
			}{
				{Embedding: embedding},
			},
		}
		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(resp)
	}))
	defer server.Close()

	embedder := NewOpenAIEmbedder("test-key", WithEmbeddingModel("text-embedding-3-large"))
	embedder.client.Transport = &urlRewriter{
		target:    server.URL,
		transport: server.Client().Transport,
	}

	_, err := embedder.Embed(context.Background(), "hello")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if receivedModel != "text-embedding-3-large" {
		t.Errorf("expected model 'text-embedding-3-large', got %q", receivedModel)
	}
}

// urlRewriter is an http.RoundTripper that redirects all requests to a target URL.
type urlRewriter struct {
	target    string
	transport http.RoundTripper
}

func (u *urlRewriter) RoundTrip(req *http.Request) (*http.Response, error) {
	req = req.Clone(req.Context())
	req.URL.Scheme = "http"
	req.URL.Host = strings.TrimPrefix(u.target, "http://")
	transport := u.transport
	if transport == nil {
		transport = http.DefaultTransport
	}
	return transport.RoundTrip(req)
}

