package worker

import (
	"context"
	"fmt"
	"log/slog"

	"github.com/google/uuid"
	"github.com/jackc/pgx/v5/pgxpool"
	pgvector "github.com/pgvector/pgvector-go"
	"github.com/riverqueue/river"

	"github.com/ketang/flotsam/api/internal/provider"
)

// EmbedArgs are the arguments for an embedding generation job.
type EmbedArgs struct {
	ItemID  uuid.UUID `json:"item_id"`
	Content string    `json:"content"`
}

func (EmbedArgs) Kind() string { return "embed" }

// EmbedWorker generates vector embeddings for item content.
type EmbedWorker struct {
	river.WorkerDefaults[EmbedArgs]
	Pool     *pgxpool.Pool
	Embedder provider.Embedder
}

func (w *EmbedWorker) Work(ctx context.Context, job *river.Job[EmbedArgs]) error {
	slog.InfoContext(ctx, "worker: embed: processing",
		"item_id", job.Args.ItemID,
		"content_len", len(job.Args.Content),
	)

	if w.Embedder == nil {
		slog.WarnContext(ctx, "worker: embed: no embedder configured, skipping",
			"item_id", job.Args.ItemID,
		)
		return nil
	}

	if job.Args.Content == "" {
		slog.WarnContext(ctx, "worker: embed: empty content, skipping",
			"item_id", job.Args.ItemID,
		)
		return nil
	}

	// Generate embedding
	embedding, err := w.Embedder.Embed(ctx, job.Args.Content)
	if err != nil {
		return fmt.Errorf("worker: embed: generate embedding: %w", err)
	}

	// Store embedding in database
	vec := pgvector.NewVector(embedding)
	_, err = w.Pool.Exec(ctx,
		`UPDATE items SET embedding = $1, updated_at = now() WHERE id = $2`,
		vec, job.Args.ItemID)
	if err != nil {
		return fmt.Errorf("worker: embed: store embedding: %w", err)
	}

	slog.InfoContext(ctx, "worker: embed: done",
		"item_id", job.Args.ItemID,
		"dimensions", len(embedding),
	)
	return nil
}

