package provider

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"time"
)

// Classification holds structured metadata extracted from item content.
type Classification struct {
	Category    string   `json:"category"`
	Topics      []string `json:"topics"`
	People      []string `json:"people"`
	ActionItems []string `json:"action_items"`
	Sensitivity string   `json:"sensitivity_suggestion"` // "normal", "sensitive", "private"
	Summary     string   `json:"summary"`
}

// Classifier extracts structured metadata from text content.
type Classifier interface {
	Classify(ctx context.Context, content string) (*Classification, error)
}

const (
	openAIChatURL          = "https://api.openai.com/v1/chat/completions"
	openAIClassifyModel    = "gpt-4o-mini"
	classifyTimeout        = 60 * time.Second
	maxClassifyInputLen    = 30000 // rough char limit to fit in context window
	classifySystemPrompt   = `You are a metadata extraction assistant. Analyze the provided content and extract structured metadata as JSON with these fields:

- "category": a single category label (e.g., "article", "note", "recipe", "meeting-notes", "tutorial", "reference", "personal", "work", "research")
- "topics": array of 1-5 relevant topic tags (lowercase, hyphenated)
- "people": array of people mentioned by name (empty array if none)
- "action_items": array of action items or tasks mentioned (empty array if none)
- "sensitivity_suggestion": one of "normal", "sensitive", or "private" based on content nature
- "summary": a 1-2 sentence summary of the content

Respond with ONLY valid JSON, no markdown or explanation.`
)

// OpenAIClassifier extracts metadata via the OpenAI Chat Completions API.
type OpenAIClassifier struct {
	apiKey string
	model  string
	client *http.Client
}

// OpenAIClassifierOption configures an OpenAIClassifier.
type OpenAIClassifierOption func(*OpenAIClassifier)

// WithClassificationModel sets a custom model name.
func WithClassificationModel(model string) OpenAIClassifierOption {
	return func(c *OpenAIClassifier) { c.model = model }
}

// WithClassificationHTTPClient sets a custom HTTP client (useful for testing).
func WithClassificationHTTPClient(c *http.Client) OpenAIClassifierOption {
	return func(cl *OpenAIClassifier) { cl.client = c }
}

// NewOpenAIClassifier creates an OpenAI-based classifier.
func NewOpenAIClassifier(apiKey string, opts ...OpenAIClassifierOption) *OpenAIClassifier {
	c := &OpenAIClassifier{
		apiKey: apiKey,
		model:  openAIClassifyModel,
		client: &http.Client{Timeout: classifyTimeout},
	}
	for _, opt := range opts {
		opt(c)
	}
	return c
}

type chatRequest struct {
	Model          string        `json:"model"`
	Messages       []chatMessage `json:"messages"`
	ResponseFormat *respFormat   `json:"response_format,omitempty"`
}

type chatMessage struct {
	Role    string `json:"role"`
	Content string `json:"content"`
}

type respFormat struct {
	Type string `json:"type"`
}

type chatResponse struct {
	Choices []struct {
		Message struct {
			Content string `json:"content"`
		} `json:"message"`
	} `json:"choices"`
	Error *struct {
		Message string `json:"message"`
	} `json:"error"`
}

// Classify extracts structured metadata from the given content.
func (c *OpenAIClassifier) Classify(ctx context.Context, content string) (*Classification, error) {
	if content == "" {
		return nil, fmt.Errorf("provider: classify: empty input")
	}

	// Truncate to avoid exceeding context window
	if len(content) > maxClassifyInputLen {
		content = content[:maxClassifyInputLen]
	}

	body, err := json.Marshal(chatRequest{
		Model: c.model,
		Messages: []chatMessage{
			{Role: "system", Content: classifySystemPrompt},
			{Role: "user", Content: content},
		},
		ResponseFormat: &respFormat{Type: "json_object"},
	})
	if err != nil {
		return nil, fmt.Errorf("provider: classify: marshal request: %w", err)
	}

	req, err := http.NewRequestWithContext(ctx, http.MethodPost, openAIChatURL, bytes.NewReader(body))
	if err != nil {
		return nil, fmt.Errorf("provider: classify: build request: %w", err)
	}
	req.Header.Set("Content-Type", "application/json")
	req.Header.Set("Authorization", "Bearer "+c.apiKey)

	resp, err := c.client.Do(req)
	if err != nil {
		return nil, fmt.Errorf("provider: classify: http: %w", err)
	}
	defer func() { _ = resp.Body.Close() }()

	respBody, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("provider: classify: read response: %w", err)
	}

	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("provider: classify: api status %d: %s", resp.StatusCode, string(respBody))
	}

	var result chatResponse
	if err := json.Unmarshal(respBody, &result); err != nil {
		return nil, fmt.Errorf("provider: classify: unmarshal response: %w", err)
	}

	if result.Error != nil {
		return nil, fmt.Errorf("provider: classify: api error: %s", result.Error.Message)
	}

	if len(result.Choices) == 0 || result.Choices[0].Message.Content == "" {
		return nil, fmt.Errorf("provider: classify: empty response from model")
	}

	var classification Classification
	if err := json.Unmarshal([]byte(result.Choices[0].Message.Content), &classification); err != nil {
		return nil, fmt.Errorf("provider: classify: parse classification json: %w", err)
	}

	return &classification, nil
}

