package provider

import (
	"context"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
)

func TestOpenAIClassifier_Classify(t *testing.T) {
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			t.Errorf("expected POST, got %s", r.Method)
		}
		if r.Header.Get("Authorization") != "Bearer test-key" {
			t.Errorf("unexpected authorization header: %s", r.Header.Get("Authorization"))
		}
		if r.Header.Get("Content-Type") != "application/json" {
			t.Errorf("unexpected content type: %s", r.Header.Get("Content-Type"))
		}

		var req chatRequest
		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
			t.Fatalf("failed to decode request: %v", err)
		}
		if req.Model != "gpt-4o-mini" {
			t.Errorf("unexpected model: %s", req.Model)
		}
		if req.ResponseFormat == nil || req.ResponseFormat.Type != "json_object" {
			t.Errorf("expected json_object response format")
		}
		if len(req.Messages) != 2 {
			t.Fatalf("expected 2 messages, got %d", len(req.Messages))
		}
		if req.Messages[0].Role != "system" {
			t.Errorf("expected system message first, got %s", req.Messages[0].Role)
		}
		if req.Messages[1].Content != "Test article about Go programming" {
			t.Errorf("unexpected user content: %s", req.Messages[1].Content)
		}

		classification := Classification{
			Category:    "article",
			Topics:      []string{"go", "programming"},
			People:      []string{},
			ActionItems: []string{},
			Sensitivity: "normal",
			Summary:     "An article about Go programming.",
		}
		classJSON, _ := json.Marshal(classification)

		resp := chatResponse{
			Choices: []struct {
				Message struct {
					Content string `json:"content"`
				} `json:"message"`
			}{
				{Message: struct {
					Content string `json:"content"`
				}{Content: string(classJSON)}},
			},
		}
		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(resp)
	}))
	defer server.Close()

	classifier := NewOpenAIClassifier("test-key")
	classifier.client.Transport = &urlRewriter{
		target:    server.URL,
		transport: server.Client().Transport,
	}

	result, err := classifier.Classify(context.Background(), "Test article about Go programming")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if result.Category != "article" {
		t.Errorf("expected category 'article', got %q", result.Category)
	}
	if len(result.Topics) != 2 || result.Topics[0] != "go" {
		t.Errorf("unexpected topics: %v", result.Topics)
	}
	if result.Sensitivity != "normal" {
		t.Errorf("expected sensitivity 'normal', got %q", result.Sensitivity)
	}
	if result.Summary != "An article about Go programming." {
		t.Errorf("unexpected summary: %q", result.Summary)
	}
}

func TestOpenAIClassifier_EmptyInput(t *testing.T) {
	classifier := NewOpenAIClassifier("test-key")
	_, err := classifier.Classify(context.Background(), "")
	if err == nil {
		t.Fatal("expected error for empty input")
	}
	if !strings.Contains(err.Error(), "empty input") {
		t.Errorf("expected 'empty input' error, got: %v", err)
	}
}

func TestOpenAIClassifier_APIError(t *testing.T) {
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
		w.WriteHeader(http.StatusTooManyRequests)
		_, _ = w.Write([]byte(`{"error": {"message": "rate limited"}}`))
	}))
	defer server.Close()

	classifier := NewOpenAIClassifier("test-key")
	classifier.client.Transport = &urlRewriter{
		target:    server.URL,
		transport: server.Client().Transport,
	}

	_, err := classifier.Classify(context.Background(), "some content")
	if err == nil {
		t.Fatal("expected error for API error response")
	}
	if !strings.Contains(err.Error(), "api status 429") {
		t.Errorf("expected status 429 error, got: %v", err)
	}
}

func TestOpenAIClassifier_EmptyResponse(t *testing.T) {
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
		w.Header().Set("Content-Type", "application/json")
		_, _ = w.Write([]byte(`{"choices": []}`))
	}))
	defer server.Close()

	classifier := NewOpenAIClassifier("test-key")
	classifier.client.Transport = &urlRewriter{
		target:    server.URL,
		transport: server.Client().Transport,
	}

	_, err := classifier.Classify(context.Background(), "some content")
	if err == nil {
		t.Fatal("expected error for empty response")
	}
	if !strings.Contains(err.Error(), "empty response") {
		t.Errorf("expected 'empty response' error, got: %v", err)
	}
}

func TestOpenAIClassifier_MalformedJSON(t *testing.T) {
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
		resp := chatResponse{
			Choices: []struct {
				Message struct {
					Content string `json:"content"`
				} `json:"message"`
			}{
				{Message: struct {
					Content string `json:"content"`
				}{Content: "not valid json"}},
			},
		}
		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(resp)
	}))
	defer server.Close()

	classifier := NewOpenAIClassifier("test-key")
	classifier.client.Transport = &urlRewriter{
		target:    server.URL,
		transport: server.Client().Transport,
	}

	_, err := classifier.Classify(context.Background(), "some content")
	if err == nil {
		t.Fatal("expected error for malformed JSON")
	}
	if !strings.Contains(err.Error(), "parse classification json") {
		t.Errorf("expected 'parse classification json' error, got: %v", err)
	}
}

func TestOpenAIClassifier_Truncation(t *testing.T) {
	var receivedContent string
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		var req chatRequest
		_ = json.NewDecoder(r.Body).Decode(&req)
		receivedContent = req.Messages[1].Content

		classification := Classification{
			Category:    "article",
			Topics:      []string{"test"},
			Sensitivity: "normal",
			Summary:     "Test.",
		}
		classJSON, _ := json.Marshal(classification)

		resp := chatResponse{
			Choices: []struct {
				Message struct {
					Content string `json:"content"`
				} `json:"message"`
			}{
				{Message: struct {
					Content string `json:"content"`
				}{Content: string(classJSON)}},
			},
		}
		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(resp)
	}))
	defer server.Close()

	classifier := NewOpenAIClassifier("test-key")
	classifier.client.Transport = &urlRewriter{
		target:    server.URL,
		transport: server.Client().Transport,
	}

	longInput := strings.Repeat("a", maxClassifyInputLen+1000)
	_, err := classifier.Classify(context.Background(), longInput)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(receivedContent) != maxClassifyInputLen {
		t.Errorf("expected input truncated to %d, got %d", maxClassifyInputLen, len(receivedContent))
	}
}

func TestOpenAIClassifier_CustomModel(t *testing.T) {
	var receivedModel string
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		var req chatRequest
		_ = json.NewDecoder(r.Body).Decode(&req)
		receivedModel = req.Model

		classification := Classification{
			Category:    "note",
			Topics:      []string{"test"},
			Sensitivity: "normal",
			Summary:     "Test.",
		}
		classJSON, _ := json.Marshal(classification)

		resp := chatResponse{
			Choices: []struct {
				Message struct {
					Content string `json:"content"`
				} `json:"message"`
			}{
				{Message: struct {
					Content string `json:"content"`
				}{Content: string(classJSON)}},
			},
		}
		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(resp)
	}))
	defer server.Close()

	classifier := NewOpenAIClassifier("test-key", WithClassificationModel("gpt-4o"))
	classifier.client.Transport = &urlRewriter{
		target:    server.URL,
		transport: server.Client().Transport,
	}

	_, err := classifier.Classify(context.Background(), "hello")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if receivedModel != "gpt-4o" {
		t.Errorf("expected model 'gpt-4o', got %q", receivedModel)
