	Storage     *storage.Client  // nil if S3 not configured
	Transcriber provider.Transcriber
	Embedder    provider.Embedder   // nil if no embedding provider configured
	Classifier  provider.Classifier // nil if no classification provider configured
}

// Registry holds registered workers and allows setting the River client after
// creation (resolves the circular dependency: workers need RiverClient, but
// RiverClient needs the workers collection).
type Registry struct {
	Workers        *river.Workers
	pageFetchWorker   *PageFetchWorker
	transcribeWorker  *TranscribeWorker
}

// SetRiverClient sets the River client on workers that need to enqueue follow-up jobs.
func (reg *Registry) SetRiverClient(client *river.Client[pgx.Tx]) {
	reg.pageFetchWorker.RiverClient = client
	reg.transcribeWorker.RiverClient = client
}

// NewRegistry creates a Registry with all job types registered.
func NewRegistry(deps Deps) *Registry {
	items := item.New(deps.Pool)

	pfw := &PageFetchWorker{Items: items, Storage: deps.Storage}
	tw := &TranscribeWorker{
		Storage:     deps.Storage,
		Transcriber: deps.Transcriber,
		Pool:        deps.Pool,
	}

	workers := river.NewWorkers()
	river.AddWorker(workers, pfw)
	river.AddWorker(workers, tw)
	river.AddWorker(workers, &EmbedWorker{
		Pool:     deps.Pool,
		Embedder: deps.Embedder,
	})
	river.AddWorker(workers, &ClassifyWorker{})
	river.AddWorker(workers, &S3UploadWorker{})

	return &Registry{
		Workers:          workers,
		pageFetchWorker:  pfw,
		transcribeWorker: tw,
	}
}

